import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';

const ProductDetails = () => {
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const { id } = useParams();

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`/api/products/${id}`);
      setProduct(response.data.product);
      setError('');
    } catch (err) {
      setError('Failed to fetch product details');
      console.error('Error fetching product:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading product details...</div>;
  }

  if (error || !product) {
    return (
      <div className="container">
        <div className="error">{error || 'Product not found'}</div>
        <Link to="/" className="btn btn-primary mt-20">Back to Products</Link>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="product-detail-container">
        <Link to="/" className="btn btn-secondary mb-20">← Back to Products</Link>

        <div className="product-detail-card">
          <div className="product-detail-image">
            <img 
              src={product.image} 
              alt={product.name}
              className="product-detail-img"
            />
          </div>

          <div className="product-detail-info">
            <h1 className="product-detail-name">{product.name}</h1>

            <div className="product-detail-price">
              ${product.price.toFixed(2)}
            </div>

            <div className="product-detail-category">
              <span className="category-badge">
                {product.category.charAt(0).toUpperCase() + product.category.slice(1)}
              </span>
              {product.inStock ? (
                <span className="stock-badge in-stock">In Stock</span>
              ) : (
                <span className="stock-badge out-of-stock">Out of Stock</span>
              )}
            </div>

            <div className="product-detail-description">
              <h3>Description</h3>
              <p>{product.description}</p>
            </div>

            <div className="product-detail-meta">
              <p><strong>Product ID:</strong> {product._id}</p>
              <p><strong>Added on:</strong> {new Date(product.createdAt).toLocaleDateString()}</p>
              {product.updatedAt !== product.createdAt && (
                <p><strong>Last updated:</strong> {new Date(product.updatedAt).toLocaleDateString()}</p>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;
